#include "hirct/Target/GenCocotb.h"

#include "hirct/Analysis/IRAnalysis.h"
#include <cctype>
#include <cerrno>
#include <cstring>
#include <fstream>
#include <iostream>
#include <sys/stat.h>

namespace hirct {

static constexpr const char *AUTO_GENERATED_HEADER_PY =
    "# AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

static std::string to_lower(const std::string &s) {
  std::string r;
  r.reserve(s.size());
  for (char c : s)
    r += static_cast<char>(tolower(static_cast<unsigned char>(c)));
  return r;
}

static bool ends_with(const std::string &s, const std::string &suffix) {
  return s.size() >= suffix.size() &&
         s.compare(s.size() - suffix.size(), suffix.size(), suffix) == 0;
}

static bool starts_with(const std::string &s, const std::string &prefix) {
  return s.size() >= prefix.size() && s.compare(0, prefix.size(), prefix) == 0;
}

GenCocotb::GenCocotb(circt::hw::HWModuleOp hw_module)
    : hw_module_(hw_module) {}

bool GenCocotb::emit(const std::string &output_dir) {
  std::vector<SimplePort> in_ports;
  std::vector<SimplePort> out_ports;
  std::string module;

  for (const auto &p : hirct::get_input_ports(hw_module_))
    in_ports.push_back({p.name, static_cast<int>(p.width)});
  for (const auto &p : hirct::get_output_ports(hw_module_))
    out_ports.push_back({p.name, static_cast<int>(p.width)});
  module = hw_module_.getSymName().str();

  std::string cocotb_dir = output_dir + "/cocotb";
  if (mkdir(cocotb_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    std::cerr << "GenCocotb: cannot create directory: " << cocotb_dir << ": "
              << strerror(errno) << "\n";
    return false;
  }

  std::string path = cocotb_dir + "/test_" + module + ".py";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenCocotb: cannot open " << path << "\n";
    return false;
  }

  std::string clock_name;
  std::string reset_name;
  bool active_low = false;
  for (const auto &p : in_ports) {
    if (clock_name.empty() && hirct::is_clock_port(p.name))
      clock_name = p.name;
    if (reset_name.empty() && hirct::is_reset_port(p.name)) {
      reset_name = p.name;
      active_low = hirct::is_active_low_reset(p.name);
    }
  }
  for (const auto &p : out_ports) {
    if (clock_name.empty() && hirct::is_clock_port(p.name))
      clock_name = p.name;
    if (reset_name.empty() && hirct::is_reset_port(p.name)) {
      reset_name = p.name;
      active_low = hirct::is_active_low_reset(p.name);
    }
  }

  bool has_clock = !clock_name.empty();
  int reset_active = active_low ? 0 : 1;
  int reset_inactive = active_low ? 1 : 0;

  ofs << AUTO_GENERATED_HEADER_PY;
  ofs << "import cocotb\n";
  ofs << "from cocotb.clock import Clock\n";
  ofs << "from cocotb.triggers import RisingEdge, Timer\n";
  ofs << "\n\n";

  emit_test_reset(ofs, clock_name, reset_name, has_clock, reset_active,
                  reset_inactive, out_ports);
  ofs << "\n\n";
  emit_test_random_stimulus(ofs, clock_name, reset_name, has_clock,
                            reset_active, reset_inactive, in_ports);

  return true;
}

void GenCocotb::emit_test_reset(std::ofstream &ofs,
                                const std::string &clock_name,
                                const std::string &reset_name, bool has_clock,
                                int reset_active, int reset_inactive,
                                const std::vector<SimplePort> &out_ports) {
  ofs << "@cocotb.test()\n";
  ofs << "async def test_reset(dut):\n";
  ofs << "    \"\"\"Reset sanity: verify outputs after reset\"\"\"\n";

  if (has_clock) {
    ofs << "    clock = Clock(dut." << clock_name << ", 10, units=\"ns\")\n";
    ofs << "    cocotb.start_soon(clock.start())\n";
    if (!reset_name.empty()) {
      ofs << "    dut." << reset_name << ".value = " << reset_active << "\n";
      ofs << "    await RisingEdge(dut." << clock_name << ")\n";
      ofs << "    await RisingEdge(dut." << clock_name << ")\n";
      ofs << "    dut." << reset_name << ".value = " << reset_inactive << "\n";
      ofs << "    await RisingEdge(dut." << clock_name << ")\n";
    } else {
      ofs << "    await RisingEdge(dut." << clock_name << ")\n";
      ofs << "    await RisingEdge(dut." << clock_name << ")\n";
    }
  } else {
    ofs << "    await Timer(1, units=\"ns\")\n";
  }

  for (const auto &p : out_ports) {
    ofs << "    _ = dut." << p.name << ".value\n";
  }
}

void GenCocotb::emit_test_random_stimulus(std::ofstream &ofs,
                                          const std::string &clock_name,
                                          const std::string &reset_name,
                                          bool has_clock, int reset_active,
                                          int reset_inactive,
                                          const std::vector<SimplePort> &in_ports) {
  ofs << "@cocotb.test()\n";
  ofs << "async def test_random_stimulus(dut):\n";
  ofs << "    \"\"\"Random stimulus: random inputs for 100 cycles\"\"\"\n";

  if (has_clock) {
    ofs << "    clock = Clock(dut." << clock_name << ", 10, units=\"ns\")\n";
    ofs << "    cocotb.start_soon(clock.start())\n";
    if (!reset_name.empty()) {
      ofs << "    dut." << reset_name << ".value = " << reset_active << "\n";
      ofs << "    for _ in range(2):\n";
      ofs << "        await RisingEdge(dut." << clock_name << ")\n";
      ofs << "    dut." << reset_name << ".value = " << reset_inactive << "\n";
    }
  }

  ofs << "    import random\n";
  ofs << "    for _ in range(100):\n";

  for (const auto &p : in_ports) {
    bool is_clock = hirct::is_clock_port(p.name);
    bool is_reset = hirct::is_reset_port(p.name);
    if (is_clock || is_reset)
      continue;
    ofs << "        dut." << p.name << ".value = random.getrandbits(" << p.width
        << ")\n";
  }

  if (has_clock) {
    ofs << "        await RisingEdge(dut." << clock_name << ")\n";
  } else {
    ofs << "        await Timer(1, units=\"ns\")\n";
  }
}

} // namespace hirct
